import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';

function App() {
  const [etapa, setEtapa] = useState('login'); // login, escolha, acao
  const [modo, setModo] = useState(''); // 'retirada' ou 'devolucao'
  const [codigo, setCodigo] = useState("");
  const [usuario, setUsuario] = useState(null);
  const [mensagem, setMensagem] = useState("Aguardando crachá...");
  const inputRef = useRef(null);

  useEffect(() => { inputRef.current?.focus(); }, [etapa]);

  const handleKeyPress = async (e) => {
    if (e.key === 'Enter') {
      const valor = codigo.trim();
      if (etapa === 'login') await realizarLogin(valor);
      else if (etapa === 'acao') await processarAcao(valor);
      setCodigo("");
    }
  };

  const realizarLogin = async (codBarras) => {
    try {
      const res = await axios.post('http://localhost:3001/login', { codBarras });
      setUsuario(res.data);
      setEtapa('escolha');
      setMensagem(`Olá, ${res.data.nome}! O que deseja fazer?`);
    } catch (err) { setMensagem("❌ Crachá inválido."); }
  };

  const processarAcao = async (ferramentacod) => {
    const url = modo === 'retirada' ? '/emprestimo/retirada' : '/emprestimo/devolucao';
    const dados = modo === 'retirada' 
      ? { usuarioId: usuario.id, ferramentacod } 
      : { ferramentacod };

    try {
      const res = await axios.post(`http://localhost:3001${url}`, dados);
      setMensagem(`✅ ${res.data}`);
      setTimeout(() => { setEtapa('login'); setUsuario(null); setMensagem("Aguardando crachá..."); }, 3000);
    } catch (err) { setMensagem("❌ Erro na operação."); }
  };

  return (
    <div style={{ textAlign: 'center', fontFamily: 'Arial', marginTop: '50px' }}>
      <img src="/logo-tsea.png" style={{ width: '150px' }} alt="logo" />
      <h1>TSEA Rastreabilidade</h1>
      
      <div style={{ border: '1px solid #ccc', padding: '20px', display: 'inline-block', borderRadius: '10px' }}>
        <h2>{mensagem}</h2>

        {etapa === 'escolha' && (
          <div>
            <button onClick={() => { setModo('retirada'); setEtapa('acao'); setMensagem("Bipe a ferramenta para RETIRADA"); }} style={styles.btn}>PEGAR FERRAMENTA</button>
            <button onClick={() => { setModo('devolucao'); setEtapa('acao'); setMensagem("Bipe a ferramenta para DEVOLUÇÃO"); }} style={styles.btnDev}>ENTREGAR FERRAMENTA</button>
          </div>
        )}

        {(etapa === 'login' || etapa === 'acao') && (
          <input 
            ref={inputRef}
            value={codigo} 
            onChange={(e) => setCodigo(e.target.value)} 
            onKeyDown={handleKeyPress} 
            placeholder="Aguardando bip..."
            style={styles.input}
          />
        )}
      </div>
    </div>
  );
}

const styles = {
  input: { padding: '10px', fontSize: '18px', marginTop: '10px' },
  btn: { padding: '15px 20px', fontSize: '16px', margin: '10px', cursor: 'pointer', backgroundColor: '#0055ff', color: 'white', border: 'none', borderRadius: '5px' },
  btnDev: { padding: '15px 20px', fontSize: '16px', margin: '10px', cursor: 'pointer', backgroundColor: '#28a745', color: 'white', border: 'none', borderRadius: '5px' }
};

export default App;
